import{_ as i,o as t,c as a,ag as e}from"./chunks/framework.DXGyWiRo.js";const p="/media/202508/2025-08-14_144428_2192300.3918909370689997.png",n="/media/202508/2025-08-14_145137_2225590.8225816224999526.png",o="/media/202508/2025-08-14_150750_5450960.014445194903701553.png",s="/media/202508/2025-08-14_150727_8026500.49549866376843366.png",r="/media/202508/2025-08-14_150817_8424580.25909336925828363.png",_="/media/202508/2025-08-14_151112_7798880.3297666692734377.png",c="/media/202508/2025-08-14_151130_0795280.19147670254299698.png",b=JSON.parse('{"title":"语音合成配置","description":"","frontmatter":{"title":"语音合成配置"},"headers":[],"relativePath":"app-config/tts-config.md","filePath":"app-config/tts-config.md","lastUpdated":null}'),u={name:"app-config/tts-config.md"};function m(d,l,g,f,h,x){return t(),a("div",null,[...l[0]||(l[0]=[e('<p>语音合成配置概述</p><p>语音合成配置项是提供AIUI传统语义链路或通用大模型链路下，全链路语音合成服务开关和发音人选配。开启该配置项，服务请求时AIUI云服务就直接采用交互回复内容直接进行播报。不同链路表现如下：</p><p><strong>- 传统语义交互链路</strong></p><ul><li>未开启应用后处理</li></ul><p>合成服务直接调用技能结果中 answer.text 字段取值直接合成。</p><ul><li>开启了应用后处理</li></ul><p>合成服务直接调用后处理结果中 answer.text 字段取值直接合成。</p><p><strong>- 通用大模型交互链路</strong></p><p>合成服务直接采用大模型结果的回复语进行合成【由于大模型结果流式下发，云端才用分段合成】</p><p>相关配置项：</p><p><img src="'+p+'" alt="" title="null"></p><h2 id="音色更换" tabindex="-1">音色更换 <a class="header-anchor" href="#音色更换" aria-label="Permalink to &quot;音色更换&quot;">​</a></h2><p>在发音人下拉列表下可以选择需要的发音人选配，展示的发音人也可以通过筛选条件进行筛选。</p><ul><li>场景 <ul><li>全部场景 <strong>注意</strong>：超拟人发音人在该场景下才能查看</li><li>通用场景</li><li>方言场景</li><li>多语种场景</li><li>民族语场景</li></ul></li><li>年龄段 <ul><li>全部年龄段</li><li>女童声</li><li>男童声</li><li>成人女声</li><li>成人男声</li></ul></li></ul><p><img src="'+n+'" alt="" title="null"></p><h2 id="发音人授权查看" tabindex="-1">发音人授权查看 <a class="header-anchor" href="#发音人授权查看" aria-label="Permalink to &quot;发音人授权查看&quot;">​</a></h2><p>在发音人下拉列表下，黑色可选发音人代表已授权的，灰色代表未授权。具体表现如下：</p><ul><li>黑色可选发音人 <ul><li>永久免费发音人</li><li>付费发音人 注意：需查看真实授权的截止日期，可选不一定代表可用</li></ul></li><li>灰色不可选发音人 展示授权申请方式</li></ul><p><img src="'+o+'" alt="" title="null"><img src="'+s+'" alt="" title="null"><img src="'+r+'" alt="" title="null"></p><h2 id="发音人试听" tabindex="-1">发音人试听 <a class="header-anchor" href="#发音人试听" aria-label="Permalink to &quot;发音人试听&quot;">​</a></h2><p>该能力是提供给开发者在线试听发音人音色的，试听方式有两种：</p><ul><li>在发音人选择界面直接点击播放按钮进行试听</li><li>选择发音人后自定义合成文本、调节合成参数进行合成试听 注意：该方式仅支持可选发音人操作</li></ul><p><img src="'+_+'" alt="" title="null"></p><p><img src="'+c+'" alt="" title="null"></p>',24)])])}const q=i(u,[["render",m]]);export{b as __pageData,q as default};
